```
#include <iostream>
#include <fstream>
#include <string>

using namespace std;

int main() {
    string wordToFind;
    int count = 0;

    ifstream inputFile;
    inputFile.open("input.txt");

    if (inputFile.is_open()) {
        while (getline(inputFile, wordToFind)) {
            if (wordToFind.find("specific word")!= string::npos) {
                count++;
            }
        }
        cout << "Number of occurrences of specific word: " << count << endl;
    } else {
        cout << "Unable to open file" << endl;
    }

    inputFile.close();
    return 0;
}
```
